"use client";

import { LogOut, LayoutDashboard, Users, CalendarDays, FileSpreadsheet, MessageSquare, ClipboardCheck, BookOpen, Search, Bell, GraduationCap, ChevronDown, PieChart } from "lucide-react";
import Image from "next/image";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useState, useEffect } from "react";

export default function TeacherDashboard() {
  const router = useRouter();
  const [isProfileDropdownOpen, setIsProfileDropdownOpen] = useState(false);
  const [showLogoutModal, setShowLogoutModal] = useState(false);
  const [attendanceMarked, setAttendanceMarked] = useState(false);
  const [teacherName, setTeacherName] = useState("Teacher");
  const [teacherDept, setTeacherDept] = useState("Department");
  const [teacherInitials, setTeacherInitials] = useState("T");

  useEffect(() => {
    const dataStr = localStorage.getItem("userData");
    if (dataStr) {
      try {
        const userData = JSON.parse(dataStr);
        const name = userData?.name || userData?.full_name || "Teacher";
        const dept = userData?.department || userData?.subject || "Department";
        setTeacherName(name);
        setTeacherDept(dept);
        
        // Generate initials
        const parts = name.trim().split(" ");
        if (parts.length > 1) {
          setTeacherInitials((parts[0][0] + parts[parts.length - 1][0]).toUpperCase());
        } else if (name.length > 0) {
          setTeacherInitials(name.substring(0, 2).toUpperCase());
        }
      } catch {
        // Fallback silently
      }
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem("userData");
    router.push("/");
  };

  return (
    <div className="flex h-screen bg-slate-50 font-sans">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-slate-200 flex flex-col shadow-sm z-20">
        <div className="h-16 flex items-center px-6 border-b border-slate-100 flex-shrink-0">
          <Image src="/skoolms.png" alt="Logo" width={110} height={28} className="object-contain w-auto h-auto" priority />
          <span className="ml-2 px-2 py-0.5 bg-green-100 text-green-700 rounded text-xs font-bold uppercase tracking-wider">Staff</span>
        </div>
        <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
          <Link href="/teacher" className="flex items-center px-4 py-3 bg-[#4CAF50]/10 text-[#4CAF50] rounded-lg font-medium transition-colors">
            <LayoutDashboard className="w-5 h-5 mr-3" /> Dashboard
          </Link>
          <a href="#" className="flex items-center px-4 py-3 text-slate-600 hover:bg-slate-50 hover:text-slate-900 rounded-lg transition-colors">
            <ClipboardCheck className="w-5 h-5 mr-3" /> Attendance
          </a>
          <a href="#" className="flex items-center px-4 py-3 text-slate-600 hover:bg-slate-50 hover:text-slate-900 rounded-lg transition-colors">
            <Users className="w-5 h-5 mr-3" /> Classes
          </a>
          <a href="#" className="flex items-center px-4 py-3 text-slate-600 hover:bg-slate-50 hover:text-slate-900 rounded-lg transition-colors">
            <GraduationCap className="w-5 h-5 mr-3" /> Students
          </a>
          <Link href="/teacher/grades" className="flex items-center px-4 py-3 text-slate-600 hover:bg-slate-50 hover:text-slate-900 rounded-lg transition-colors group">
            <FileSpreadsheet className="w-5 h-5 mr-3 flex-shrink-0" /> <span className="truncate">Grades & Reports</span>
          </Link>
          <Link href="/teacher/assignments" className="flex items-center px-4 py-3 text-slate-600 hover:bg-slate-50 hover:text-slate-900 rounded-lg transition-colors group">
            <BookOpen className="w-5 h-5 mr-3 flex-shrink-0" /> <span className="truncate">Assignments</span>
          </Link>
          <Link href="/teacher/schedule" className="flex items-center px-4 py-3 text-slate-600 hover:bg-slate-50 hover:text-slate-900 rounded-lg transition-colors group">
            <CalendarDays className="w-5 h-5 mr-3 flex-shrink-0" /> <span className="truncate">Schedule</span>
          </Link>
          <Link href="/teacher/parent-connect" className="flex items-center px-4 py-3 text-slate-600 hover:bg-slate-50 hover:text-slate-900 rounded-lg transition-colors group">
            <MessageSquare className="w-5 h-5 mr-3 flex-shrink-0" /> <span className="truncate">Parent Connect</span>
          </Link>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden relative">
        {/* Header */}
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 lg:px-8 z-10 flex-shrink-0">
          <div className="flex items-center w-64 lg:w-96 relative">
            <Search className="w-4 h-4 text-slate-400 absolute left-3" />
            <input type="text" placeholder="Search resources or students..." className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-100 rounded-full text-sm focus:bg-white focus:border-[#4CAF50] focus:ring-1 focus:ring-[#4CAF50] outline-none transition-all" />
          </div>
          <div className="flex items-center space-x-6">
            <button className="relative p-2 text-slate-400 hover:text-[#4CAF50] transition-colors rounded-full hover:bg-green-50">
              <Bell className="w-5 h-5" />
            </button>
            <div className="relative">
              <div 
                className="flex items-center gap-3 border-l pl-6 border-slate-200 cursor-pointer group"
                onClick={() => setIsProfileDropdownOpen(!isProfileDropdownOpen)}
              >
                <div className="text-right hidden md:block">
                  <p className="text-sm font-semibold text-slate-800 group-hover:text-[#4CAF50] transition-colors">{teacherName}</p>
                  <p className="text-xs text-slate-500">{teacherDept}</p>
                </div>
                <div className="w-9 h-9 text-white font-bold bg-[#4CAF50] rounded-full flex items-center justify-center ring-2 ring-white shadow-sm group-hover:scale-105 transition-transform">
                  {teacherInitials}
                </div>
                <ChevronDown className="w-4 h-4 text-slate-400 group-hover:text-[#4CAF50] transition-colors" />
              </div>

              {isProfileDropdownOpen && (
                <div className="absolute right-0 mt-3 w-48 bg-white border border-slate-100 rounded-xl shadow-lg py-1 z-50 animate-in fade-in slide-in-from-top-2">
                  <Link 
                    href="/teacher/insights"
                    className="w-full px-4 py-2.5 text-left flex items-center text-slate-700 hover:bg-slate-50 hover:text-[#4CAF50] transition-colors text-sm font-medium"
                    onClick={() => setIsProfileDropdownOpen(false)}
                  >
                    <PieChart className="w-4 h-4 mr-3" /> Insights
                  </Link>
                  <div className="h-px bg-slate-100 my-1"></div>
                  <button 
                    onClick={() => {
                      setIsProfileDropdownOpen(false);
                      setShowLogoutModal(true);
                    }}
                    className="w-full px-4 py-2.5 text-left flex items-center text-red-600 hover:bg-red-50 hover:text-red-700 transition-colors text-sm font-medium"
                  >
                    <LogOut className="w-4 h-4 mr-3" /> Logout
                  </button>
                </div>
              )}
            </div>
          </div>
        </header>

        {/* Content */}
        <div className="flex-1 overflow-auto p-6 lg:p-8">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-8">
            <h1 className="text-2xl font-bold text-slate-800">Welcome back, {teacherName.split(' ')[0]}! ≡ƒæï</h1>
            <div className="space-x-4">
              <button 
                onClick={() => setAttendanceMarked(true)}
                disabled={attendanceMarked}
                className={`px-5 py-2.5 text-white rounded-xl shadow-sm transition-all font-semibold text-sm flex items-center gap-2 ${attendanceMarked ? 'bg-slate-100 text-slate-500 cursor-not-allowed border border-slate-200 shadow-none' : 'bg-[#4CAF50] hover:bg-[#43a047] hover:shadow hover:-translate-y-0.5'}`}
              >
                {attendanceMarked ? (
                  <>
                    <ClipboardCheck className="w-4 h-4 text-green-500" /> Attendance Marked
                  </>
                ) : (
                  <>
                    <ClipboardCheck className="w-4 h-4" /> Mark Today&apos;s Attendance
                  </>
                )}
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-lg hover:-translate-y-1 transition-all duration-300">
              <span className="text-slate-500 text-sm font-medium">Classes Today</span>
              <span className="text-3xl font-bold mt-3 text-slate-300">- <span className="text-lg text-slate-200 font-normal">/ -</span></span>
            </div>
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-lg hover:-translate-y-1 transition-all duration-300">
              <span className="text-slate-500 text-sm font-medium">Pending Grading</span>
              <span className="text-3xl font-bold mt-3 text-slate-300">- <span className="text-sm text-slate-200 font-normal">submissions</span></span>
            </div>
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-lg hover:-translate-y-1 transition-all duration-300">
              <span className="text-slate-500 text-sm font-medium">Avg Class Attendance</span>
              <span className="text-3xl font-bold mt-3 text-slate-300">-%</span>
            </div>
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-lg hover:-translate-y-1 transition-all duration-300">
              <span className="text-slate-500 text-sm font-medium">Next Period</span>
              <span className="text-lg font-bold mt-3 text-slate-300">- <br/><span className="text-xs text-transparent select-none bg-slate-50 px-2 py-0.5 rounded">-</span></span>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            {/* Upcoming Classes */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6 flex flex-col hover:shadow-lg hover:-translate-y-1 transition-all duration-300">
              <div className="flex justify-between items-center mb-6 flex-none">
                <h2 className="text-lg font-bold text-slate-800">Today&apos;s Schedule</h2>
                <a href="#" className="text-sm text-[#4CAF50] hover:text-[#388E3C] hover:underline font-semibold transition-colors">View Full Timetable</a>
              </div>
              <div className="flex-1 space-y-4">
                {[
                  { time: "09:00 AM", class: "8th Grade Science", room: "Room 102", status: "Completed", type:"past" },
                  { time: "11:30 AM", class: "10th Grade Math", room: "Room 205", status: "Upcoming", type:"next" },
                  { time: "01:00 PM", class: "12th Grade Advanced Calculus", room: "Lab 4", status: "Upcoming", type:"future" },
                  { time: "02:45 PM", class: "9th Grade Math", room: "Room 201", status: "Upcoming", type:"future" },
                ].map((item, i) => (
                  <div key={i} className={`flex items-start p-4 rounded-xl border transition-all duration-300 hover:shadow-md hover:-translate-y-1 ${item.type === 'next' ? 'border-[#4CAF50] bg-green-50/50' : 'border-slate-100 hover:border-slate-200 hover:bg-slate-50'}`}>
                    <div className={`text-sm font-bold w-20 flex-shrink-0 pt-0.5 ${item.type === 'past' ? 'text-slate-400' : 'text-slate-600'}`}>{item.time}</div>
                    <div className="flex-1 ml-4 border-l-2 border-slate-100 pl-4">
                      <h3 className={`font-semibold ${item.type === 'next' ? 'text-[#388E3C] text-lg' : item.type === 'past' ? 'text-slate-500' : 'text-slate-800'}`}>{item.class}</h3>
                      <p className="text-sm text-slate-500 mt-1 flex items-center">
                        <span className={`w-1.5 h-1.5 rounded-full mr-2 ${item.type === 'past' ? 'bg-slate-200' : 'bg-slate-400'}`}></span>
                        {item.room}
                      </p>
                    </div>
                    {item.type === 'past' && <span className="px-2.5 py-1 bg-slate-100 text-slate-500 rounded-md text-xs font-semibold self-start ml-2">Done</span>}
                    {item.type === 'next' && <span className="px-2.5 py-1 bg-green-100 text-green-700 rounded-md text-xs font-bold self-start ml-2 flex items-center gap-1.5 shadow-sm"><span className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></span> Now</span>}
                  </div>
                ))}
              </div>
            </div>

            {/* Quick Actions & Recent Activity */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6 flex flex-col hover:shadow-lg hover:-translate-y-1 transition-all duration-300">
              <div className="flex justify-between items-center mb-6 flex-none">
                <h2 className="text-lg font-bold text-slate-800">Recent Submissions</h2>
                <a href="#" className="text-sm text-[#4CAF50] hover:text-[#388E3C] hover:underline font-semibold transition-colors">See all</a>
              </div>
              <div className="flex-1 overflow-y-auto pr-1 space-y-3 scrollbar-thin scrollbar-thumb-slate-200 scrollbar-track-transparent">
                {[
                  { name: "Algebra Midterm", from: "10th Grade", status: "Pending Review", count: "32/32" },
                  { name: "Calculus Assignment 4", from: "12th Grade", status: "Reviewed", count: "18/20" },
                  { name: "Weekly Quiz 2", from: "9th Grade Math", status: "Graded", count: "45/45" },
                ].map((task, i) => (
                  <div key={i} className="flex justify-between items-center p-4 border border-slate-100 rounded-xl hover:border-[#4CAF50]/30 hover:bg-green-50/10 hover:shadow-md hover:-translate-y-1 transition-all duration-300 group cursor-pointer">
                    <div>
                      <h4 className="font-semibold text-slate-800 group-hover:text-[#4CAF50] transition-colors">{task.name}</h4>
                      <p className="text-xs text-slate-500 font-medium mt-1 flex items-center">
                        <Users className="w-3 h-3 mr-1" /> {task.from}
                      </p>
                    </div>
                    <div className="text-right flex flex-col items-end">
                      <span className={`text-[10px] uppercase tracking-wider font-bold px-2 py-0.5 rounded-full mb-1.5 ${task.status === 'Pending Review' ? 'text-amber-700 bg-amber-100/80 border border-amber-200' : 'text-[#388E3C] bg-green-100/80 border border-green-200'}`}>
                        {task.status}
                      </span>
                      <p className="text-xs text-slate-500 font-semibold">{task.count} <span className="font-normal opacity-80">received</span></p>
                    </div>
                  </div>
                ))}

                <button className="w-full mt-4 py-3.5 border-2 border-dashed border-slate-200 rounded-xl text-slate-500 hover:border-[#4CAF50] hover:text-[#4CAF50] hover:bg-green-50/50 transition-all font-bold text-sm flex items-center justify-center gap-2 group">
                  <span className="w-5 h-5 rounded-full bg-slate-100 text-slate-500 group-hover:bg-[#4CAF50] group-hover:text-white flex items-center justify-center transition-colors">+</span> Create New Assignment
                </button>
              </div>
            </div>
          </div>
        </div>
      </main>

      {/* Logout Confirmation Modal */}
      {showLogoutModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-8 flex flex-col items-center text-center">
              <div className="w-16 h-16 bg-red-50 rounded-2xl flex items-center justify-center mb-6 shadow-sm border border-red-100">
                <LogOut className="w-8 h-8 text-red-500" />
              </div>
              <h3 className="text-2xl font-extrabold text-slate-900 mb-2">Ready to Leave?</h3>
              <p className="text-slate-500 mb-8 max-w-xs text-sm leading-relaxed">
                You will need to sign in again to access your classes and manage assignments.
              </p>
              <div className="flex gap-3 w-full">
                <button
                  onClick={() => setShowLogoutModal(false)}
                  className="flex-1 px-4 py-3 bg-slate-50 border border-slate-200 text-slate-700 rounded-xl font-bold hover:bg-slate-100 hover:text-slate-900 transition-colors focus:ring-4 focus:ring-slate-100 focus:outline-none"
                >
                  Cancel
                </button>
                <button
                  onClick={handleLogout}
                  className="flex-1 px-4 py-3 bg-red-500 text-white rounded-xl font-bold hover:bg-red-600 transition-colors focus:ring-4 focus:ring-red-100 focus:outline-none shadow-sm hover:shadow"
                >
                  Logout
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
